const { Manifold, label } = api;

// ---------------------------------------------------------------------------
// Treasure chest: brown box body + rounded (half-cylinder) lid +
// gold trim straps that WRAP the curved lid + a gold lock plate with keyhole.
// Right-handed, Z-up. Front (lock side) faces -Y.
// ---------------------------------------------------------------------------

const bodyW = 20; // X
const bodyD = 12; // Y
const bodyH = 10; // Z (body sits z=0..10)
const lidR = 6; // lid half-cylinder radius
const lidAxisZ = bodyH; // lid cylinder centerline height

// ---- Body --------------------------------------------------------------
const body = Manifold.cube([bodyW, bodyD, bodyH], true).translate([0, 0, bodyH / 2]);

// ---- Lid: half cylinder, axis along X, centered at z=bodyH ----
const lidCyl = Manifold.cylinder(bodyW, lidR, lidR, 48)
  .rotate([0, 90, 0])
  .translate([-bodyW / 2, 0, lidAxisZ]);
// cut everything below the centerline so we keep only the top half
const lidCut = Manifold.cube([bodyW + 4, bodyD + 4, lidR + 2], true)
  .translate([0, 0, lidAxisZ - (lidR + 2) / 2]);
const lid = lidCyl.subtract(lidCut);

// ---- Strap geometry knobs ---------------------------------------------
const strapW = 1.4; // band width (along its travel direction = X)
const proud = 0.35; // how far trim stands proud of a flat face
const sink = 0.6; // how far trim sinks into the body to guarantee union
const strapX = [-6, 0, 6]; // x positions; lid bands + vertical body straps share these
const frontFaceY = -bodyD / 2; // front (-Y) plane
// center-Y for a (sink+proud)-deep band that sits on a face at +-bodyD/2,
// sunk `sink` into the body and standing `proud` out:
const faceBandCY = bodyD / 2 - (sink - proud) / 2; // magnitude; negate for front

// ---- Horizontal body straps (rings around the box sides) --------------
function ring(z) {
  const outer = Manifold.cube([bodyW + proud * 2, bodyD + proud * 2, strapW], true);
  const inner = Manifold.cube([bodyW - sink * 2, bodyD - sink * 2, strapW + 1], true);
  return outer.subtract(inner).translate([0, 0, z]);
}
const ringLo = ring(2.6);
const ringHi = ring(7.6);

// ---- Curved lid bands: a cylindrical SHELL concentric with the lid,
//      intersected with a thin slab so it becomes a narrow band that
//      hugs the lid's curved surface. ------------------------------------
function lidBand(x) {
  // shell: ring between (lidR - sink) and (lidR + proud), same axis as lid
  const rOuter = lidR + proud;
  const rInner = lidR - sink;
  const shellOuter = Manifold.cylinder(strapW, rOuter, rOuter, 48);
  const shellInner = Manifold.cylinder(strapW + 2, rInner, rInner, 48).translate([0, 0, -1]);
  let shell = shellOuter.subtract(shellInner);
  // orient axis along X and center the band slab at x.
  // After rotate([0,90,0]) the cylinder height (Z=0..strapW) maps to X=0..strapW,
  // so shift by -strapW/2 to center the band on x.
  shell = shell.rotate([0, 90, 0]).translate([x - strapW / 2, 0, lidAxisZ]);
  // keep only the upper half (above the centerline) so it sits on the lid
  const keepTop = Manifold.cube([strapW + 2, (lidR + proud) * 2 + 2, (lidR + proud) + 2], true)
    .translate([x, 0, lidAxisZ + ((lidR + proud) + 2) / 2 - 0.001]);
  const band = shell.intersect(keepTop);
  // Drop a short tab at the FRONT and BACK seam so each lid band visually
  // continues onto the body face (and overlaps body material to union).
  // These hug the flat front/back faces (y = +-bodyD/2), not the curved sides,
  // so they don't bump out past the lid ends.
  const tabH = 2.6; // reaches down from the seam (z=bodyH)
  const tab = Manifold.cube([strapW, sink + proud, tabH], true);
  const tabFront = tab.translate([x, -faceBandCY, bodyH - tabH / 2 + 0.6]);
  const tabBack = tab.translate([x, faceBandCY, bodyH - tabH / 2 + 0.6]);
  return Manifold.union([band, tabFront, tabBack]);
}
const lidBands = Manifold.union(strapX.map(lidBand));

// ---- Vertical body straps on the front (-Y) face, aligned with bands ---
// They run the full body height and meet the lid-band front tabs at the seam,
// so the strap reads as one continuous gold band from base to lid.
function frontVStrap(x) {
  return Manifold.cube([strapW, sink + proud, bodyH + 0.4], true)
    .translate([x, -faceBandCY, bodyH / 2]);
}
const vStraps = Manifold.union(strapX.map(frontVStrap));

// ---- Corner caps on the four vertical body edges (gold) ----------------
function cornerCap(sx, sy) {
  const t = 1.1;
  const cap = Manifold.cube([t, t, bodyH], true)
    .translate([sx * (bodyW / 2 - t / 2 + proud / 2), sy * (bodyD / 2 - t / 2 + proud / 2), bodyH / 2]);
  return cap;
}
const caps = Manifold.union([
  cornerCap(-1, -1), cornerCap(1, -1), cornerCap(-1, 1), cornerCap(1, 1),
]);

// ---- Feet at base corners (gold) ---------------------------------------
function foot(sx, sy) {
  const fw = 2.0,
    fh = 1.4;
  return Manifold.cube([fw, fw, fh], true)
    .translate([sx * (bodyW / 2 - fw / 2 + 0.2), sy * (bodyD / 2 - fw / 2 + 0.2), fh / 2 - 0.5]);
}
const feet = Manifold.union([
  foot(-1, -1), foot(1, -1), foot(-1, 1), foot(1, 1),
]);

// ---- Lock plate on the front (-Y), centered, with a keyhole carved in --
const plateW = 4.6; // X
const plateH = 5.2; // Z
const plateProud = 0.9; // how far the plate stands off the body face
const plateSink = 1.0; // how far it sinks in (guarantees union)
const plateDepth = plateProud + plateSink;
const plateFront = frontFaceY - plateProud; // outer Y of plate
const plateCY = frontFaceY - plateProud + plateDepth / 2; // = frontFaceY+(sink-proud)/2
const plateZ = 5.6; // straddles the lid/body seam a touch

let lockPlate = Manifold.cube([plateW, plateDepth, plateH], true)
  .translate([0, plateCY, plateZ]);
// round the top of the plate with a half-disc cap
const plateCap = Manifold.cylinder(plateDepth, plateW / 2, plateW / 2, 32)
  .rotate([90, 0, 0])
  .translate([0, plateCY + plateDepth / 2, plateZ + plateH / 2 - 0.1]);
lockPlate = Manifold.union([lockPlate, plateCap]);

// keyhole: round hole + slot, bored into the FRONT of the plate as a BLIND
// pocket (does not pass through, so topology stays genus 0). Cylinder along
// +Z; rotate([-90,0,0]) maps +Z -> +Y so it bores inward from the front.
const khZ = plateZ + 0.6;
const khDepth = plateProud + 0.6; // start outside, stop inside plate
const khStartY = plateFront - 0.3; // just outside the front face
const keyRound = Manifold.cylinder(khDepth, 0.6, 0.6, 24)
  .rotate([-90, 0, 0])
  .translate([0, khStartY, khZ]);
const keySlot = Manifold.cube([0.55, khDepth, 1.7], true)
  .translate([0, khStartY + khDepth / 2, khZ - 1.05]);
const keyhole = Manifold.union([keyRound, keySlot]);
lockPlate = lockPlate.subtract(keyhole);

// ---- Hasp: a raised gold strap over the lid/body seam, above the plate --
const haspW = 1.8;
const haspProud = plateProud + 0.25; // stands slightly proud of the plate
const haspDepth = haspProud + sink;
const haspCY = frontFaceY - haspProud + haspDepth / 2;
const hasp = Manifold.cube([haspW, haspDepth, 5.0], true)
  .translate([0, haspCY, bodyH - 0.2]); // bridges body top into the lid

// ---- Compose with labels for coloring ----------------------------------
const goldTrim = Manifold.union([ringLo, ringHi, lidBands, vStraps, caps, feet]);

const chestBody = label(body, 'body');
const chestLid = label(lid, 'lid');
const trim = label(goldTrim, 'trim');
const lock = label(Manifold.union([lockPlate, hasp]), 'lock');

return Manifold.union([chestBody, chestLid, trim, lock]);
